// ../../packages/cascade-publish/dist/process-diff.js
import { execFileSync } from "node:child_process";
import { readFileSync } from "node:fs";
import path2 from "node:path";
async function processDiff(input) {
  const raw2 = execFileSync("git", ["diff", "--name-status", "-M", input.beforeSha, input.afterSha, "--", input.docsDir], { cwd: input.repoDir, encoding: "utf-8" });
  const changes = parseDiffOutput(raw2).filter((change) => change.path.endsWith(".md"));
  let processed = 0;
  const errors2 = [];
  for (const change of changes) {
    const sourceRepoPath = `${input.repoName}/${change.path}`;
    try {
      if (change.changeType === "deleted") {
        const lastKnownContent = execFileSync("git", ["show", `${input.beforeSha}:${change.path}`], {
          cwd: input.repoDir,
          encoding: "utf-8"
        });
        const result = await archiveDoc(input.config, { lastKnownContent, sourceRepoPath });
        console.log(`[cascade-publish] archived ${change.path} -> ${result.path} (hardDeleted: ${result.hardDeleted})`);
      } else {
        const content3 = readFileSync(path2.join(input.repoDir, change.path), "utf-8");
        const result = await publishDoc(input.config, {
          content: content3,
          sourceRepoPath,
          gitAuthorEmail: input.gitAuthorEmail
        });
        console.log(`[cascade-publish] published ${change.path} -> ${result.path} (moved: ${result.moved})`);
      }
      processed++;
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      console.error(`[cascade-publish] FAILED ${change.path}: ${message}`);
      errors2.push({ path: change.path, error: message });
    }
  }
  return { processed, errors: errors2 };
}

// src/index.ts
function requireEnv(name) {
  const value = process.env[name];
  if (!value) throw new Error(`Missing required env var ${name}`);
  return value;
}
async function run() {
  const config = {
    baseUrl: requireEnv("CASCADE_BASE_URL"),
    siteName: requireEnv("CASCADE_SITE_NAME"),
    apiKey: requireEnv("CASCADE_API_KEY"),
    documentationPageContentTypeId: requireEnv("CASCADE_DOC_CONTENT_TYPE_ID"),
    navOutputContentTypeId: requireEnv("CASCADE_NAV_CONTENT_TYPE_ID")
  };
  const result = await processDiff({
    config,
    repoDir: process.cwd(),
    repoName: requireEnv("GITHUB_REPOSITORY"),
    beforeSha: requireEnv("BEFORE_SHA"),
    afterSha: requireEnv("AFTER_SHA"),
    docsDir: core2.getInput("docs-dir") || "docs",
    gitAuthorEmail: process.env["GIT_AUTHOR_EMAIL"] || "actions@github.com"
  });
  core2.info(`processed ${result.processed} file(s), ${result.errors.length} error(s)`);
  for (const error2 of result.errors) {
    core2.error(`${error2.path}: ${error2.error}`);
  }
  if (result.errors.length > 0) {
    core2.setFailed(`${result.errors.length} doc(s) failed to publish`);
  }
}
run().catch((err) => {
  core2.setFailed(err instanceof Error ? err.message : String(err));
});
